/* Types */
export type ActiveSkillView = {
  skill_id: string;
  name: string;
  source: string;
  activation_mode: string;
};

export type AddCatalogSourceRequestPayload = {
  id: string;
  display_name: string;
  kind: string;
  url: string;
  api_key_env: string | null;
  priority: number | null;
  default_trust: string | null;
  enabled: boolean | null;
  cache_ttl_seconds: number;
};

export type AgentSettingsInput = {
  scope: AgentSettingsScope;
  name: string;
  description: string;
  tools: string[];
  modelProfile: string | null;
  skills: string[];
  nicknameCandidates: string[];
  enabled: boolean;
  instructions: string;
};

export type AgentSettingsScope = "Builtin" | "User" | "Project";

export type AgentSettingsView = {
  settingsId: string;
  name: string;
  description: string;
  scope: AgentSettingsScope;
  path: string;
  tools: string[];
  modelProfile: string | null;
  skills: string[];
  nicknameCandidates: string[];
  enabled: boolean;
  instructions: string;
  effective: boolean;
  shadowedBy: string | null;
  valid: boolean;
  validationError: string | null;
  editable: boolean;
  deletable: boolean;
};

/**  Metadata for a file attached to a user message. */
export type AttachmentInfo = {
  /**  Absolute filesystem path. */
  path: string;
  /**  Display filename. */
  name: string;
  /**  MIME type (e.g. "image/png", "application/pdf"). */
  mime_type: string;
};

export type BuildInfoResponse = {
  version: string;
  git_hash: string;
  build_time: string;
};

export type CatalogQueryRequest = {
  keyword: string | null;
  category: string | null;
  /**  "unverified" | "community" | "verified" */
  trust_min: string | null;
  source: string | null;
  limit: number;
};

export type CatalogSourceViewResponse = {
  id: string;
  display_name: string;
  kind: string;
  url: string;
  api_key_env: string | null;
  priority: number;
  default_trust: string;
  enabled: boolean;
  cache_ttl_seconds: number;
  last_error: string | null;
};

export type CheckMcpHealthResponse = {
  tools: McpToolDefResponse[];
  healthy: boolean;
  error: string | null;
};

export type ConfigScope = "Builtin" | "User" | "Project" | "Local";

/**  Result of a connectivity test to an MCP server. */
export type ConnectivityResult =
  /**  The server is reachable and returned tools. */
  | {
      status: "connected";
      /**  Number of tools discovered on the server. */
      tool_count: number;
    }
  /**  The server could not be reached or the operation timed out. */
  | {
      status: "failed";
      /**  Human-readable reason for the failure. */
      reason: string;
    };

export type ConnectivityTestResult = {
  ok: boolean;
  error: string | null;
};

export type EffectiveAgentView = {
  value: AgentSettingsView;
  source: ConfigScope;
  overrides: ConfigScope | null;
  enabled: boolean;
  disabledBy: ConfigScope | null;
  writable: boolean;
  deletable: boolean;
};

